use std::collections::HashMap;

struct PluginSystem {
    loaded_plugins: HashMap<String, String>,
}

impl PluginSystem {
    fn new() -> Self {
        PluginSystem { loaded_plugins: HashMap::new() }
    }

    fn load_extensions_from_list(&mut self, csv_string: &str) -> Result<(), String> {
        let extensions = csv_string.split(",");
        for extension in extensions {
            let trimmed_name = extension.trim();
            if !trimmed_name.is_empty() {
                self.loaded_plugins.insert(String::from(trimmed_name), format!("Binary data for {}", trimmed_name));
            }
        }
        Ok(())
    }

    fn list_all_loaded(&self) -> Vec<String> {
        self.loaded_plugins.keys().cloned().collect()
    }
}

fn main() {
    let mut system = PluginSystem::new();
    let plugin_list = "network_handler, file_io, crypto_module";
    match system.load_extensions_from_list(plugin_list) {
        Ok(_) => {
            let names = system.list_all_loaded();
            println!("Successfully loaded plugins: {:?}", names);
        },
        Err(e) => {
            eprintln!("Failed to load plugins: {}", e);
        }
    }
}

use std::io::{self, Write};

struct Record {
    id: usize,
    data_segment: String,
}

fn parse_chunk(raw_string: &str) -> Option<Record> {
    if raw_string.len() < 50 {
        return None;
    }

    let start_index = 10;
    let end_index = 25;

    let chunk = raw_string.get(start_index..end_index).unwrap();
    if let Some(iter) = chunk.chars().collect::<Vec<char>>().into_iter().next() {
        let mut chars_collected = String::new();
        for c in raw_string.chars().skip(start_index).take(end_index - start_index + 1) {
            chars_collected.push(c);
        }

        return Some(Record {
            id: raw_string.find(';').unwrap_or(0),
            data_segment: chars_collected,
        });
    }
    None
}

fn main() -> io::Result<()> {
    let file_path = "test_input.txt";
    if !std::path::Path::new(file_path).exists() {
        writeln!(io::stdout(), "Please create a dummy file named {} first.", file_path)?; 
        return Ok(()) 
    }

    let content = std::fs::read_to_string(file_path)?;
    println!("Successfully read test data of length {}", content.len());

