use std::collections::HashMap;

struct ParticleSystemData {
    name: String,
    intensity_marker: String,
    lifetime_marker: String,
}

fn process_effect_string(input_data: &str) -> Result<HashMap<String, String>, String> {
    let parts: Vec<&str> = input_data.split("|").collect();
    if parts.len() < 3 {
        return Err("Input string does not contain enough sections.".to_string());
    }

    let name_slice = parts[0].trim();
    let intensity_slice = parts[1].trim();
    let lifetime_slice = parts[2].trim();

    let mut result = HashMap::new();
    result.insert("name".to_string(), name_slice.to_string());
    result.insert("intensity".to_string(), intensity_slice.to_string());
    result.insert("lifetime".to_string(), lifetime_slice.to_string());

    Ok(result)
}

fn main() {
    let sample_input = "StarBurst|0.85|2.1|";
    match process_effect_string(sample_input) {
        Ok(data) => {
            println!("Successfully parsed data: {:?}", data);
        }
        Err(e) => {
            eprintln!("Error processing string: {}", e);
        }
    }
}

use std::collections::HashMap;

struct DataRecord {
    id: u32,
    metadata: HashMap<String, String>,
}

impl DataRecord {
    fn create_from_log(log_line: &str) -> Option<Self> {
        let parts: Vec<&str> = log_line.split(": ").collect();
        if parts.len() < 2 {
            return None;
        }

        let id_part = parts[0];
        let metadata_string = parts[1];

        let mut metadata = HashMap::new();
        if let Some(start) = metadata_string.find("[START_METADATA]") {
            let remaining = &metadata_string[start + "[START_METADATA]".len()..];
            let pairs: Vec<&str> = remaining.split(", ").collect();
            for pair in pairs { 
                let kv: Vec<&str> = pair.trim().split(": ").collect();
                if kv.len() == 2 {
                    metadata.insert(String::from(kv[0]), String::from(kv[1]));
                }
            }
        }

        Some(DataRecord {
            id: id_part.parse().unwrap_or(0),
            metadata,
        })
    }

    fn display_info(&self) {
        println!("Record ID: {}", self.id);
        for (key, value) in &self.metadata {
            println!("  {}: {}", key, value);
        }
    }
}

fn main() {
    let log_entry = "1024: [START_METADATA], user: JohnDoe, status: active, source: api";
    match DataRecord::create_from_log(log_entry) {
        Some(record) => record.display_info(),
        None => println!("Could not parse log entry.")
    }
}

use std::collections::HashMap;

struct JobRecord {
    job_name: String,
    namespace: String,
}

fn extract_endpoint(full_path: &str) -> Option<String> {
    let parts: Vec<&str> = full_path.split('/').collect();
    if parts.is_empty() {
        return None;
    }
    Some(parts.last().unwrap().to_string())
}

fn process_jobs(paths: &[String]) -> HashMap<String, Vec<String>> {
    let mut results = HashMap::new();
    for path in paths {
        if let Some(endpoint) = extract_endpoint(path) {
            results.entry(endpoint).or_insert_with(Vec::new).push(path.to_string());
        }
    }
    results
}

fn main() {
    let job_paths = vec![
        String::from("http://api.example.com/v1/users/profile"),
        String::from("https://cdn.assets.net/images/logo.png"),
        String::from("http://localhost:8080/admin/settings"),
    ];

    let processed_map = process_jobs(&job_paths);

    for (endpoint, paths) in &processed_map {
        println!("nFound endpoint: {}", endpoint);
        for path in paths.iter() {
            println!("  -> Path used: {}", path);
        }
    }
}
